class Solution {
    public int minimumChanges(String s, int k) {
        int n = s.length();
        int[][] cost = new int[n][n];
        for (int i = 0; i < n; i++) {
            for (int j = i; j < n; j++) {
                cost[i][j] = minChanges(s, i, j);
            }
        }
        int[][] dp = new int[n][k + 1];
        for (int i = 0; i < n; i++) {
            for (int j = 0; j <= k; j++) {
                dp[i][j] = n;
            }
        }
        dp[0][1] = cost[0][0];
        for (int i = 1; i < n; i++) {
            for (int j = 1; j <= Math.min(i + 1, k); j++) {
                for (int m = i; m >= j - 1; m--) {
                    dp[i][j] = Math.min(dp[i][j], dp[m - 1][j - 1] + cost[m][i]);
                }
            }
        }
        return dp[n - 1][k];
    }

    private int minChanges(String s, int start, int end) {
        int len = end - start + 1;
        int min = len;
        for (int d = 1; d < len; d++) {
            if (len % d == 0) {
                int changes = 0;
                for (int i = 0; i < d; i++) {
                    int[] count = new int[26];
                    for (int j = i; j < len; j += d) {
                        count[s.charAt(start + j) - 'a']++;
                    }
                    int maxCount = 0;
                    for (int c : count) {
                        maxCount = Math.max(maxCount, c);
                    }
                    changes += (len / d - maxCount);
                }
                min = Math.min(min, changes);
            }
        }
        return min;
    }
}
